import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Chart as ChartJS,
  CategoryScale, LinearScale, BarElement, ArcElement,
  PointElement, LineElement, Title, Tooltip, Legend,
  Filler
} from 'chart.js';
import { Bar, Doughnut, Line } from 'react-chartjs-2';
import api from '../../services/api';
import { FiUsers, FiCalendar, FiClock, FiUserCheck, FiTrendingUp, FiStar, FiHeart } from 'react-icons/fi';
import AnimatedIcon from '../../components/common/AnimatedIcon';

ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, PointElement, LineElement, Title, Tooltip, Legend, Filler);

const AnimatedNumber = ({ value, label, icon: Icon, color, bgColor, animation = 'float' }) => {
  const [displayed, setDisplayed] = useState(0);
  const ref = useRef(null);

  useEffect(() => {
    let start = 0;
    const end = value;
    const duration = 1500;
    const stepTime = Math.max(Math.floor(duration / end), 16);
    const timer = setInterval(() => {
      start += 1;
      setDisplayed(start);
      if (start >= end) clearInterval(timer);
    }, stepTime);
    return () => clearInterval(timer);
  }, [value]);

  return (
    <div
      ref={ref}
      className="stat-card animate-slide-up"
      style={{ cursor: 'default' }}
    >
      <div className="stat-icon" style={{ background: bgColor }}>
        <AnimatedIcon icon={Icon} size={24} color={color} animation={animation} />
      </div>
      <div className="stat-info">
        <h4 className="animated-number">{displayed}</h4>
        <p>{label}</p>
      </div>
    </div>
  );
};

const Dashboard = () => {
  const [data, setData] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    api.get('/dashboard').then(res => setData(res.data)).catch(() => {});
  }, []);

  if (!data) return <div className="loading-screen"><div className="spinner"></div></div>;

  const barData = {
    labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
    datasets: [
      {
        label: 'Hours Worked',
        data: [7.5, 8.2, 6.8, 8.5, 7.0, 2.5, 0],
        backgroundColor: ['rgba(255,123,29,0.7)', 'rgba(118,188,33,0.7)', 'rgba(52,152,219,0.7)', 'rgba(155,89,182,0.7)', 'rgba(241,196,15,0.7)', 'rgba(231,76,60,0.7)', 'rgba(149,165,166,0.7)'],
        borderColor: ['#FF7B1D', '#76BC21', '#3498DB', '#9B59B6', '#F1C40F', '#E74C3C', '#95A5A6'],
        borderWidth: 2,
        borderRadius: 6,
      }
    ]
  };

  const barOptions = {
    responsive: true,
    animation: { duration: 2000, easing: 'easeOutBounce' },
    plugins: { legend: { display: false } },
    scales: {
      y: { beginAtZero: true, grid: { color: 'rgba(0,0,0,0.05)' } },
      x: { grid: { display: false } }
    }
  };

  const doughnutData = {
    labels: ['Annual', 'Sick', 'Personal', 'Other'],
    datasets: [{
      data: [12, 5, 3, 2],
      backgroundColor: ['#FF7B1D', '#76BC21', '#3498DB', '#9B59B6'],
      borderWidth: 0,
      hoverOffset: 12,
    }]
  };

  const doughnutOptions = {
    responsive: true,
    animation: { animateRotate: true, duration: 2000 },
    plugins: {
      legend: { position: 'bottom', labels: { padding: 16, usePointStyle: true, font: { size: 11 } } }
    },
    cutout: '65%',
  };

  const lineData = {
    labels: ['Week 1', 'Week 2', 'Week 3', 'Week 4'],
    datasets: [
      {
        label: 'Employees',
        data: [42, 45, 48, data.employeeCount || 50],
        borderColor: '#FF7B1D',
        backgroundColor: 'rgba(255,123,29,0.1)',
        fill: true,
        tension: 0.4,
        pointBackgroundColor: '#FF7B1D',
        pointRadius: 5,
        pointHoverRadius: 8,
      }
    ]
  };

  const lineOptions = {
    responsive: true,
    animation: { duration: 2500, easing: 'easeInOutQuart' },
    plugins: { legend: { display: false } },
    scales: {
      y: { beginAtZero: true, grid: { color: 'rgba(0,0,0,0.05)' } },
      x: { grid: { display: false } }
    }
  };

  return (
    <div>
      <div className="stats-grid">
        <AnimatedNumber value={data.employeeCount} label="Total Employees" icon={FiUsers} color="#FF7B1D" bgColor="#fff3e0" animation="bounce" />
        <AnimatedNumber value={data.pendingLeaves?.length || 0} label="Pending Leave" icon={FiCalendar} color="#76BC21" bgColor="#e8f5e9" animation="pulse" />
        <AnimatedNumber value={data.employeesOnLeave?.length || 0} label="On Leave Today" icon={FiClock} color="#3498DB" bgColor="#e3f2fd" animation="float" />
        <AnimatedNumber value={data.candidateCount} label="Candidates" icon={FiUserCheck} color="#9B59B6" bgColor="#f3e5f5" animation="wiggle" />
      </div>

      <div className="charts-grid">
        <div className="chart-card animate-slide-up stagger-1">
          <h4><AnimatedIcon icon={FiTrendingUp} color="var(--primary)" animation="pulse" /> Weekly Hours</h4>
          <Bar data={barData} options={barOptions} />
        </div>
        <div className="chart-card animate-slide-up stagger-2">
          <h4><AnimatedIcon icon={FiStar} color="#F1C40F" animation="glow" /> Leave Distribution</h4>
          <Doughnut data={doughnutData} options={doughnutOptions} />
        </div>
        <div className="chart-card chart-full animate-slide-up stagger-3">
          <h4><AnimatedIcon icon={FiHeart} color="#E74C3C" animation="pulse" /> Employee Growth</h4>
          <Line data={lineData} options={lineOptions} />
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>
        <div className="card animate-slide-up stagger-3">
          <div className="card-header">
            <h3><FiCalendar /> Pending Leave Requests</h3>
            <button className="btn btn-sm btn-outline" onClick={() => navigate('/leave/requests')}>View All</button>
          </div>
          <div className="card-body">
            {data.pendingLeaves?.length === 0 ? (
              <p style={{ color: '#999', fontSize: 13, textAlign: 'center', padding: 20 }}>No pending leave requests.</p>
            ) : (
              <div className="table-container">
                <table>
                  <thead><tr><th>Employee</th><th>Type</th><th>Dates</th><th></th></tr></thead>
                  <tbody>
                    {data.pendingLeaves?.slice(0, 5).map((l, i) => (
                      <tr key={l._id} className="animate-fade-in" style={{ animationDelay: `${i * 0.1}s` }}>
                        <td><strong>{l.employee?.fullName}</strong></td>
                        <td><span className="status-badge status-pending">{l.leaveType?.name}</span></td>
                        <td>{new Date(l.fromDate).toLocaleDateString()} - {new Date(l.toDate).toLocaleDateString()}</td>
                        <td>
                          <button className="btn btn-sm btn-primary" onClick={() => navigate('/leave/requests')}>Review</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>

        <div className="card animate-slide-up stagger-4">
          <div className="card-header">
            <h3><FiClock /> Employees On Leave Today</h3>
          </div>
          <div className="card-body">
            {data.employeesOnLeave?.length === 0 ? (
              <p style={{ color: '#999', fontSize: 13, textAlign: 'center', padding: 20 }}>No employees on leave today.</p>
            ) : (
              <div className="table-container">
                <table>
                  <thead><tr><th>Name</th><th>Department</th></tr></thead>
                  <tbody>
                    {data.employeesOnLeave?.map(l => (
                      <tr key={l._id}>
                        <td><strong>{l.employee?.fullName}</strong></td>
                        <td>{l.employee?.department || '-'}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
